 1	import { useMemo } from 'react';
 2	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
 3	
 4	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 7	
 8	import { getDisableButtonTooltipContent } from './utils';
 9	
10	type UseStatusActionButtonsType = (isSubmitting: boolean) => {
11	  disableButtonTooltipContent: string;
12	  isCreationDisabled: boolean;
13	  isViewYAMLDisabled: boolean;
14	};
15	const useStatusActionButtons: UseStatusActionButtonsType = (isSubmitting) => {
16	  const instanceTypeVMStore = useInstanceTypeVMStore();
17	
18	  const {
19	    instanceTypeVMState: { selectedBootableVolume, selectedInstanceType, vmName },
20	  } = instanceTypeVMStore;
21	
22	  const [canCreateVM] = useAccessReview({
23	    group: VirtualMachineModel.apiGroup,
24	    namespace: instanceTypeVMStore?.vmNamespaceTarget,
25	    resource: VirtualMachineModel.plural,
26	    verb: 'create' as K8sVerb,
27	  });
28	
29	  const disableButtonTooltipContent = useMemo(
30	    () => getDisableButtonTooltipContent(instanceTypeVMStore, canCreateVM),
31	    [instanceTypeVMStore, canCreateVM],
32	  );
33	
34	  const isCreationDisabled = isSubmitting || !isEmpty(disableButtonTooltipContent);
35	
36	  return {
37	    disableButtonTooltipContent,
38	    isCreationDisabled,
39	    isViewYAMLDisabled:
40	      isEmpty(selectedBootableVolume) || isEmpty(vmName) || isEmpty(selectedInstanceType),
41	  };
42	};
43	
44	export default useStatusActionButtons;

